module example-vlan {
  namespace "http://netops.lab/vlan";
  prefix ex;

  container vlans {
    list vlan {
      key "id";
      leaf id { type uint16; }
      leaf name { type string; }
    }
  }
}

cat > models/intent/vlans.json << 'EOF'
{
  "vlans": {
    "vlan": [
      {"id": 100, "name": "DATA_VLAN"},
      {"id": 200, "name": "VOICE_VLAN"}
    ]
  }
}
EOF
python -m json.tool models/intent/vlans.json

cat > templates/vlans.j2 << 'EOF'
{% for v in vlans.vlan %}
vlan {{ v.id }}
 name {{ v.name }}
{% endfor %}
EOF
pip install jinja2
python -c "import json,jinja2; d=json.load(open('models/intent/vlans.json')); open('rendered/vlans.cfg','w').write(jinja2.Template(open('templates/vlans.j2').read()).render(**d))"
